/**
 * The stable, user-mappable error surface the shells receive across the FFI.
 */
public 
enum ApiError: Swift.Error, Equatable, Hashable, Foundation.LocalizedError {

    
    
    /**
     * The source's server could not be reached.
     */
    case NetworkUnreachable
    /**
     * A request took too long.
     */
    case Timeout
    /**
     * The source rejected the supplied credentials.
     */
    case Unauthorized
    /**
     * The requested item no longer exists at the source.
     */
    case NotFound
    /**
     * Input provided by the user was not usable.
     */
    case InvalidInput(
        /**
         * A short, plain-language reason (never contains secret material).
         */reason: String
    )
    /**
     * The response was fetched but yielded no usable channels.
     */
    case ParseFailed(
        /**
         * Channels successfully read.
         */emitted: UInt64, 
        /**
         * Entries skipped as malformed.
         */skipped: UInt64
    )
    /**
     * The local database could not be read or written.
     */
    case StorageCorrupt
    /**
     * The operation was cancelled (by the user or a departing screen).
     */
    case Cancelled
    /**
     * An unexpected internal error; the detail is in the log stream.
     */
    case Internal

    

    

    
    public var errorDescription: String? {
        String(reflecting: self)
    }
    
}

#if compiler(>=6)
extension ApiError: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeApiError: FfiConverterRustBuffer {
    typealias SwiftType = ApiError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> ApiError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .NetworkUnreachable
        case 2: return .Timeout
        case 3: return .Unauthorized
        case 4: return .NotFound
        case 5: return .InvalidInput(
            reason: try FfiConverterString.read(from: &buf)
            )
        case 6: return .ParseFailed(
            emitted: try FfiConverterUInt64.read(from: &buf), 
            skipped: try FfiConverterUInt64.read(from: &buf)
            )
        case 7: return .StorageCorrupt
        case 8: return .Cancelled
        case 9: return .Internal

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: ApiError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case .NetworkUnreachable:
            writeInt(&buf, Int32(1))
        
        
        case .Timeout:
            writeInt(&buf, Int32(2))
        
        
        case .Unauthorized:
            writeInt(&buf, Int32(3))
        
        
        case .NotFound:
            writeInt(&buf, Int32(4))
        
        
        case let .InvalidInput(reason):
            writeInt(&buf, Int32(5))
            FfiConverterString.write(reason, into: &buf)
            
        
        case let .ParseFailed(emitted,skipped):
            writeInt(&buf, Int32(6))
            FfiConverterUInt64.write(emitted, into: &buf)
            FfiConverterUInt64.write(skipped, into: &buf)
            
        
        case .StorageCorrupt:
            writeInt(&buf, Int32(7))
        
        
        case .Cancelled:
            writeInt(&buf, Int32(8))
        
        
        case .Internal:
            writeInt(&buf, Int32(9))
        
        }
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeApiError_lift(_ buf: RustBuffer) throws -> ApiError {
    return try FfiConverterTypeApiError.lift(buf)
}

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeApiError_lower(_ value: ApiError) -> RustBuffer {
    return FfiConverterTypeApiError.lower(value)
}


/**
 * Which phase of an import is currently running.
 */

public enum ImportStage: Equatable, Hashable {
    
    /**
     * Establishing the connection to the source.
     */
    case connecting
    /**
     * Streaming and parsing the playlist body.
     */
    case downloading
    /**
     * Committing the staged catalog (the staging-and-swap).
     */
    case finalizing





}

#if compiler(>=6)
extension ImportStage: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeImportStage: FfiConverterRustBuffer {
    typealias SwiftType = ImportStage

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> ImportStage {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .connecting
        
        case 2: return .downloading
        
        case 3: return .finalizing
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: ImportStage, into buf: inout [UInt8]) {
